def monotoneIncreasingDigits(n):
    s = list(str(n))
    marker = len(s)
    for i in range(len(s) - 1, 0, -1):
        if s[i-1] > s[i]:
            s[i-1] = str(int(s[i-1]) - 1)
            marker = i
    for i in range(marker, len(s)): s[i] = '9'
    return int("".join(s))

